3	import com.fasterxml.jackson.databind.JsonNode;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptDTO;
6	import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptMetaDTO;
7	import com.mzfuture.entire.checkpoint.dto.response.TranscriptFileChangeSummaryDTO;
8	import com.mzfuture.entire.checkpoint.dto.response.TranscriptFileDiffDTO;
9	import com.mzfuture.entire.checkpoint.dto.response.TranscriptMessageViewDTO;
10	import com.mzfuture.entire.checkpoint.dto.response.TranscriptToolUseDTO;
11	import org.springframework.stereotype.Component;
12	
13	import java.nio.charset.StandardCharsets;
14	import java.util.ArrayList;
15	import java.util.Collections;
16	import java.util.LinkedHashMap;
17	import java.util.List;
18	import java.util.Locale;
19	import java.util.Map;
