21	/// Parses raw `full.jsonl` / transcript text into the stable `NormalizedTranscriptDTO` used by the admin UI.
22	/// Supports OpenCode single JSON and Cursor-style NDJSON (one JSON object per line).
23	@Component
24	public class TranscriptNormalizer {
25	
26	    public static final int SCHEMA_VERSION = 1;
27	    public static final String FORMAT_CURSOR_NDJSON = "cursor_ndjson";
28	    public static final String FORMAT_OPENCODE_JSON = "opencode_json";
29	    public static final String FORMAT_UNKNOWN = "unknown";
30	
31	    // Use a local mapper: this project does not expose ObjectMapper as a Spring bean (see SessionMetadataParser).
32	    private final ObjectMapper objectMapper = new ObjectMapper();
33	
34	    /// Normalize transcript text. Never throws; on total failure returns empty messages and `unknown` format with warnings.
35	    public NormalizedTranscriptDTO normalize(String raw) {
36	        List<String> warnings = new ArrayList<>();
37	        if (raw == null) {
38	            return empty(lenBytes(""), warnings, FORMAT_UNKNOWN);
39	        }
40	        long rawBytesLength = lenBytes(raw);
41	        String trimmed = raw.trim();
42	        if (trimmed.isEmpty()) {
43	            warnings.add("Empty transcript");
44	            return empty(rawBytesLength, warnings, FORMAT_UNKNOWN);
45	        }
46	
47	        try {
48	            JsonNode root = objectMapper.readTree(trimmed);
49	            if (root.isObject()) {
50	                if (root.has("messages") && root.get("messages").isArray()) {
51	                    return parseOpenCode(root, rawBytesLength, warnings);
52	                }
53	                if (root.has("role") && root.has("message")) {
54	                    return parseCursorLines(Collections.singletonList(trimmed), rawBytesLength, warnings);
55	                }
56	            }
57	        } catch (Exception ignored) {
58	            // Try NDJSON below
59	        }
60	
61	        List<String> lines = splitNonEmptyLines(trimmed);
62	        if (!lines.isEmpty() && isLikelyCursorNdjson(lines)) {
63	            try {
64	                return parseCursorLines(lines, rawBytesLength, warnings);
65	            } catch (Exception e) {
66	                warnings.add("cursor_ndjson parse error: " + e.getMessage());
67	            }
68	        }
69	
70	        warnings.add("Unrecognized transcript format; no messages extracted");
71	        return empty(rawBytesLength, warnings, FORMAT_UNKNOWN);
72	    }
73	
74	    private static long lenBytes(String raw) {
75	        return raw.getBytes(StandardCharsets.UTF_8).length;
76	    }
77	
78	    private NormalizedTranscriptDTO empty(long rawBytesLength, List<String> warnings, String format) {
79	        NormalizedTranscriptDTO dto = new NormalizedTranscriptDTO();
80	        dto.setSchemaVersion(SCHEMA_VERSION);
81	        dto.setMeta(meta(format, rawBytesLength, warnings));
82	        dto.setStepsCount(0);
83	        dto.setFileChanges(Collections.emptyList());
84	        dto.setMessages(Collections.emptyList());
85	        return dto;
86	    }
87	
88	    private NormalizedTranscriptMetaDTO meta(String sourceFormat, long rawBytesLength, List<String> warnings) {
89	        NormalizedTranscriptMetaDTO m = new NormalizedTranscriptMetaDTO();
90	        m.setSourceFormat(sourceFormat);
91	        m.setRawBytesLength(rawBytesLength);
92	        if (!warnings.isEmpty()) {
93	            m.setWarnings(new ArrayList<>(warnings));
94	        }
95	        return m;
96	    }
97	
98	    private List<String> splitNonEmptyLines(String trimmed) {
99	        String[] parts = trimmed.split("\\R");
100	        List<String> lines = new ArrayList<>();
101	        for (String p : parts) {
102	            String s = p.trim();
103	            if (!s.isEmpty()) {
104	                lines.add(s);
105	            }
106	        }
107	        return lines;
108	    }
109	
110	    private boolean isLikelyCursorNdjson(List<String> lines) {
111	        for (String line : lines) {
112	            try {
113	                JsonNode n = objectMapper.readTree(line);
114	                if (!n.isObject() || !n.has("role") || !n.has("message")) {
115	                    return false;
116	                }
117	            } catch (Exception e) {
118	                return false;
119	            }
120	        }
121	        return true;
122	    }
123	
124	    private NormalizedTranscriptDTO parseCursorLines(List<String> lines, long rawBytesLength, List<String> warnings)
125	            throws Exception {
126	        List<TranscriptMessageViewDTO> messageViews = new ArrayList<>();
127	        int stepsCount = 0;
128	        for (String line : lines) {
129	            JsonNode n = objectMapper.readTree(line);
130	            TranscriptMessageViewDTO mv = parseCursorMessage(n);
131	            if ("user".equals(mv.getRole())) {
132	                stepsCount++;
133	            }
134	            messageViews.add(mv);
135	        }
136	        List<TranscriptFileChangeSummaryDTO> fileChanges = buildCursorFileChanges(messageViews);
137	
138	        NormalizedTranscriptDTO dto = new NormalizedTranscriptDTO();
139	        dto.setSchemaVersion(SCHEMA_VERSION);
140	        dto.setMeta(meta(FORMAT_CURSOR_NDJSON, rawBytesLength, warnings));
141	        dto.setStepsCount(stepsCount);
142	        dto.setFileChanges(fileChanges);
143	        dto.setMessages(messageViews);
144	        return dto;
145	    }
146	
147	    /// Aggregate touched files from Cursor `tool_use` blocks (path in input, StrReplace line deltas).
148	    private List<TranscriptFileChangeSummaryDTO> buildCursorFileChanges(List<TranscriptMessageViewDTO> messages) {
149	        List<PathDelta> raw = new ArrayList<>();
150	        for (TranscriptMessageViewDTO msg : messages) {
151	            if (msg.getTools() == null) {
152	                continue;
153	            }
154	            for (TranscriptToolUseDTO tu : msg.getTools()) {
155	                String normalizedPath = extractCursorPath(tu);
156	                if (normalizedPath == null || normalizedPath.isBlank()) {
157	                    continue;
158	                }
159	                int[] d = estimateCursorToolLineDelta(tu);
160	                raw.add(new PathDelta(normalizedPath, d[0], d[1]));
161	            }
162	        }
163	        if (raw.isEmpty()) {
164	            return Collections.emptyList();
165	        }
166	        List<String> distinct = raw.stream().map(p -> p.path).distinct().toList();
167	        String dirPrefix = sharedDirectoryPrefix(distinct);
168	
169	        Map<String, int[]> merged = new LinkedHashMap<>();
170	        for (PathDelta pd : raw) {
171	            String key = toRelativePath(pd.path, dirPrefix);
172	            merged.compute(key, (k, v) -> {
173	                if (v == null) {
174	                    return new int[]{pd.additions, pd.deletions};
175	                }
176	                v[0] += pd.additions;
177	                v[1] += pd.deletions;
178	                return v;
179	            });
180	        }
181	
182	        List<TranscriptFileChangeSummaryDTO> out = new ArrayList<>();
183	        for (Map.Entry<String, int[]> e : merged.entrySet()) {
184	            TranscriptFileChangeSummaryDTO s = new TranscriptFileChangeSummaryDTO();
185	            s.setFile(e.getKey());
186	            s.setAdditions(e.getValue()[0]);
187	            s.setDeletions(e.getValue()[1]);
188	            out.add(s);
189	        }
190	        return out;
191	    }
192	
193	    private static final class PathDelta {
194	        final String path;
195	        final int additions;
196	        final int deletions;
197	
198	        PathDelta(String path, int additions, int deletions) {
199	            this.path = path;
200	            this.additions = additions;
201	            this.deletions = deletions;
202	        }
203	    }
204	
205	    /// Normalize slashes; return null if no usable path field.
206	    private String extractCursorPath(TranscriptToolUseDTO tu) {
207	        JsonNode in = tu.getInput();
208	        if (in == null || !in.isObject()) {
209	            return null;
210	        }
211	        String[] keys = {"path", "file", "target_file", "target_directory", "file_path"};
212	        for (String k : keys) {
213	            if (in.has(k) && in.get(k).isTextual()) {
214	                String p = in.get(k).asText("");
215	                if (!p.isBlank()) {
216	                    return p.replace('\\', '/').trim();
217	                }
218	            }
219	        }
220	        return null;
221	    }
222	
223	    /// Rough line-delta from StrReplace / Write; other tools count as touch-only (0,0).
224	    private int[] estimateCursorToolLineDelta(TranscriptToolUseDTO tu) {
225	        String name = tu.getTool() == null ? "" : tu.getTool().trim();
226	        String lower = name.toLowerCase(Locale.ROOT);
227	        JsonNode in = tu.getInput();
228	        if (in == null || !in.isObject()) {
229	            return new int[]{0, 0};
230	        }
231	        if ("strreplace".equals(lower) || "search_replace".equals(lower) || "replace".equals(lower)) {
232	            String oldS = in.has("old_string") && in.get("old_string").isTextual() ? in.get("old_string").asText("") : "";
233	            String newS = in.has("new_string") && in.get("new_string").isTextual() ? in.get("new_string").asText("") : "";
234	            int oldLines = countLines(oldS);
235	            int newLines = countLines(newS);
236	            int add = Math.max(0, newLines - oldLines);
237	            int del = Math.max(0, oldLines - newLines);
238	            return new int[]{add, del};
239	        }
240	        if ("write".equals(lower) || "apply_patch".equals(lower)) {
241	            String contents = "";
242	            if (in.has("contents") && in.get("contents").isTextual()) {
243	                contents = in.get("contents").asText("");
244	            } else if (in.has("content") && in.get("content").isTextual()) {
245	                contents = in.get("content").asText("");
246	            }
247	            int lines = countLines(contents);
248	            return new int[]{lines, 0};
249	        }
250	        if ("delete_file".equals(lower) || "delete".equals(lower)) {
251	            return new int[]{0, 1};
252	        }
253	        return new int[]{0, 0};
254	    }
255	
256	    private static int countLines(String s) {
257	        if (s == null || s.isEmpty()) {
258	            return 0;
259	        }
260	        int n = 1;
261	        for (int i = 0; i < s.length(); i++) {
262	            if (s.charAt(i) == '\n') {
263	                n++;
264	            }
265	        }
266	        return n;
267	    }
268	
269	    /// Longest shared directory prefix ending with `/` (so relative paths are stable across tools).
270	    private static String sharedDirectoryPrefix(List<String> paths) {
271	        if (paths.isEmpty()) {
272	            return "";
273	        }
274	        if (paths.size() == 1) {
275	            String p = paths.get(0);
276	            int slash = p.lastIndexOf('/');
277	            if (slash <= 0) {
278	                return "";
279	            }
280	            return p.substring(0, slash + 1);
281	        }
282	        String first = paths.get(0);
283	        int minLen = first.length();
284	        for (String p : paths) {
285	            minLen = Math.min(minLen, commonPrefixLength(first, p));
286	        }
287	        String prefix = first.substring(0, minLen);
288	        int slash = prefix.lastIndexOf('/');
289	        if (slash <= 0) {
290	            return "";
291	        }
292	        return prefix.substring(0, slash + 1);
293	    }
294	
295	    private static int commonPrefixLength(String a, String b) {
296	        int n = Math.min(a.length(), b.length());
297	        int i = 0;
298	        while (i < n && a.charAt(i) == b.charAt(i)) {
299	            i++;
300	        }
301	        return i;
302	    }
303	
304	    private static String toRelativePath(String absoluteOrRel, String dirPrefix) {
305	        if (dirPrefix != null && !dirPrefix.isEmpty() && absoluteOrRel.startsWith(dirPrefix)) {
306	            return absoluteOrRel.substring(dirPrefix.length());
307	        }
308	        return absoluteOrRel;
309	    }
310	
311	    private TranscriptMessageViewDTO parseCursorMessage(JsonNode root) {
312	        String roleRaw = textOrNull(root, "role");
313	        String role = "user".equalsIgnoreCase(roleRaw) ? "user" : "assistant";
314	
315	        JsonNode message = root.path("message");
316	        JsonNode content = message.path("content");
317	
318	        StringBuilder textParts = new StringBuilder();
319	        List<TranscriptToolUseDTO> tools = new ArrayList<>();
320	
321	        if (content.isArray()) {
322	            for (JsonNode block : content) {
323	                String type = textOrNull(block, "type");
324	                if ("text".equals(type)) {
325	                    String t = block.has("text") ? block.get("text").asText("") : "";
326	                    if (textParts.length() > 0) {
327	                        textParts.append('\n');
328	                    }
329	                    textParts.append(t);
330	                } else if ("tool_use".equals(type)) {
331	                    TranscriptToolUseDTO tu = new TranscriptToolUseDTO();
332	                    tu.setCallID(firstNonEmpty(textOrNull(block, "id"), textOrNull(block, "call_id")));
333	                    tu.setTool(textOrNull(block, "name"));
334	                    if (block.has("input") && !block.get("input").isNull()) {
335	                        tu.setInput(block.get("input"));
336	                    }
337	                    tools.add(tu);
338	                }
339	            }
340	        }
341	
342	        TranscriptMessageViewDTO mv = new TranscriptMessageViewDTO();
343	        mv.setId("");
344	        mv.setRole(role);
345	        mv.setText(textParts.toString().trim());
346	        mv.setTools(tools);
347	        mv.setToolsCount(tools.size());
348	        return mv;
349	    }
350	
351	    private NormalizedTranscriptDTO parseOpenCode(JsonNode root, long rawBytesLength, List<String> warnings) {
352	        JsonNode info = root.path("info");
353	        String title = textOrNull(info, "title");
354	        String projectRoot = textOrNull(info, "directory");
355	
356	        Map<String, int[]> fileChangeMap = new LinkedHashMap<>();
357	        List<TranscriptMessageViewDTO> messageViews = new ArrayList<>();
358	        int stepsCount = 0;
359	
360	        JsonNode messages = root.path("messages");
361	        if (!messages.isArray()) {
362	            warnings.add("OpenCode: missing messages array");
363	        } else {
364	            for (JsonNode msg : messages) {
365	                JsonNode infoN = msg.path("info");
366	                String roleStr = textOrNull(infoN, "role");
367	                boolean isUser = "user".equalsIgnoreCase(roleStr);
368	                if (isUser) {
369	                    stepsCount++;
370	                }
371	
372	                JsonNode parts = msg.path("parts");
373	                StringBuilder textParts = new StringBuilder();
374	                String reasoning = null;
375	                List<TranscriptToolUseDTO> tools = new ArrayList<>();
376	
377	                if (parts.isArray()) {
378	                    for (JsonNode p : parts) {
379	                        String type = textOrNull(p, "type");
380	                        if ("text".equals(type)) {
381	                            String t = p.has("text") ? p.get("text").asText("") : "";
382	                            if (textParts.length() > 0) {
383	                                textParts.append('\n');
384	                            }
385	                            textParts.append(t);
386	                        } else if ("reasoning".equals(type)) {
387	                            reasoning = p.has("text") ? p.get("text").asText("") : null;
388	                        } else if ("tool".equals(type)) {
389	                            TranscriptToolUseDTO tu = new TranscriptToolUseDTO();
390	                            tu.setCallID(textOrNull(p, "callID"));
391	                            tu.setTool(textOrNull(p, "tool"));
392	                            JsonNode state = p.path("state");
393	                            if (!state.isMissingNode() && !state.isNull()) {
394	                                if (state.has("input")) {
395	                                    tu.setInput(state.get("input"));
396	                                }
397	                                if (state.has("output")) {
398	                                    tu.setOutput(state.get("output"));
399	                                }
400	                                tu.setTitle(textOrNull(state, "title"));
401	                            }
402	                            tools.add(tu);
403	                        }
404	                    }
405	                }
406	
407	                JsonNode summary = infoN.path("summary");
408	                List<TranscriptFileDiffDTO> diffs = null;
409	                if (summary.has("diffs") && summary.get("diffs").isArray()) {
410	                    diffs = new ArrayList<>();
411	                    for (JsonNode d : summary.get("diffs")) {
412	                        TranscriptFileDiffDTO fd = new TranscriptFileDiffDTO();
413	                        String file = d.has("file") ? d.get("file").asText("") : "";
414	                        fd.setFile(stripProjectRoot(file, projectRoot));
415	                        fd.setBefore(textOrNull(d, "before"));
416	                        fd.setAfter(textOrNull(d, "after"));
417	                        int add = d.has("additions") ? d.get("additions").asInt() : 0;
418	                        int del = d.has("deletions") ? d.get("deletions").asInt() : 0;
419	                        fd.setAdditions(add);
420	                        fd.setDeletions(del);
421	                        diffs.add(fd);
422	                        String rel = fd.getFile();
423	                        fileChangeMap.compute(rel, (k, v) -> {
424	                            if (v == null) {
425	                                return new int[]{add, del};
426	                            }
427	                            v[0] += add;
428	                            v[1] += del;
429	                            return v;
430	                        });
431	                    }
432	                }
433	
434	                TranscriptMessageViewDTO mv = new TranscriptMessageViewDTO();
435	                mv.setId(textOrNull(infoN, "id"));
436	                mv.setRole(isUser ? "user" : "assistant");
437	                mv.setText(textParts.toString().trim());
438	                mv.setTaskTitle(textOrNull(summary, "title"));
439	                mv.setReasoning(reasoning);
440	                JsonNode time = infoN.path("time");
441	                if (time.has("created")) {
442	                    mv.setCreatedAt(time.get("created").asLong());
443	                }
444	                mv.setTools(tools);
445	                mv.setToolsCount(tools.size());
446	                mv.setDiffs(diffs);
447	                messageViews.add(mv);
448	            }
449	        }
450	
451	        List<TranscriptFileChangeSummaryDTO> fileChanges = new ArrayList<>();
452	        for (Map.Entry<String, int[]> e : fileChangeMap.entrySet()) {
453	            TranscriptFileChangeSummaryDTO s = new TranscriptFileChangeSummaryDTO();
454	            s.setFile(e.getKey());
455	            s.setAdditions(e.getValue()[0]);
456	            s.setDeletions(e.getValue()[1]);
457	            fileChanges.add(s);
458	        }
459	
460	        NormalizedTranscriptDTO dto = new NormalizedTranscriptDTO();
461	        dto.setSchemaVersion(SCHEMA_VERSION);
462	        dto.setMeta(meta(FORMAT_OPENCODE_JSON, rawBytesLength, warnings));
463	        dto.setTitle(title);
464	        dto.setProjectRoot(projectRoot);
465	        dto.setStepsCount(stepsCount);
466	        dto.setFileChanges(fileChanges);
467	        dto.setMessages(messageViews);
468	        return dto;
469	    }
470	
471	    private static String stripProjectRoot(String filePath, String projectRoot) {
472	        if (projectRoot == null || projectRoot.isEmpty()) {
473	            return filePath;
474	        }
475	        String normalized = filePath.replace('\\', '/');
476	        String root = projectRoot.replace('\\', '/').replaceAll("/$", "");
477	        if (normalized.startsWith(root + "/")) {
478	            return normalized.substring(root.length() + 1);
479	        }
480	        return filePath;
481	    }
482	
483	    private static String textOrNull(JsonNode node, String field) {
484	        if (node == null || !node.has(field) || node.get(field).isNull()) {
485	            return null;
486	        }
487	        JsonNode v = node.get(field);
488	        if (v.isValueNode()) {
489	            return v.asText();
490	        }
491	        return null;
492	    }
493	
494	    private static String firstNonEmpty(String a, String b) {
495	        if (a != null && !a.isEmpty()) {
496	            return a;
497	        }
498	        if (b != null && !b.isEmpty()) {
499	            return b;
500	        }
501	        return a != null ? a : b;
502	    }
503	}
