package com.mzfuture.entire.checkpoint.service.impl;

import com.mzfuture.entire.checkpoint.config.CheckpointSyncProperties;
import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptDTO;
import com.mzfuture.entire.checkpoint.dto.response.SessionDTO;
import com.mzfuture.entire.checkpoint.entity.Checkpoint;
import com.mzfuture.entire.checkpoint.entity.Session;
import com.mzfuture.entire.checkpoint.git.CheckpointGitReader;
import com.mzfuture.entire.checkpoint.mapper.SessionMapper;
import com.mzfuture.entire.checkpoint.repository.CheckpointRepository;
import com.mzfuture.entire.checkpoint.repository.SessionRepository;
import com.mzfuture.entire.checkpoint.service.SessionService;
import com.mzfuture.entire.checkpoint.transcript.TranscriptNormalizer;
import com.mzfuture.entire.common.exception.Errors;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.Optional;

@Slf4j
@Service
public class SessionServiceImpl implements SessionService {

    private final SessionRepository sessionRepository;
    private final SessionMapper sessionMapper;
    private final CheckpointRepository checkpointRepository;
    private final CheckpointGitReader gitReader;
    private final CheckpointSyncProperties syncProperties;
    private final TranscriptNormalizer transcriptNormalizer;

    public SessionServiceImpl(SessionRepository sessionRepository,
                               SessionMapper sessionMapper,
                               CheckpointRepository checkpointRepository,
                               CheckpointGitReader gitReader,
                               CheckpointSyncProperties syncProperties,
                               TranscriptNormalizer transcriptNormalizer) {
        this.sessionRepository = sessionRepository;
        this.sessionMapper = sessionMapper;
        this.checkpointRepository = checkpointRepository;
        this.gitReader = gitReader;
        this.syncProperties = syncProperties;
        this.transcriptNormalizer = transcriptNormalizer;
    }

    @Override
    public SessionDTO get(Long id) {
        Session entity = sessionRepository.findById(id)
                .orElseThrow(() -> Errors.NOT_FOUND.toException("Session not found, ID: " + id));
        return sessionMapper.toDTO(entity);
    }

    @Override
    public List<SessionDTO> listByCheckpointId(Long checkpointId) {
        List<Session> sessions = sessionRepository.findByCheckpointIdOrderBySessionIndexAsc(checkpointId);
        return sessionMapper.toRows(sessions);
    }

    @Override
    public Optional<String> getContent(Long sessionId, String file) {
        Session session = sessionRepository.findById(sessionId).orElse(null);
        if (session == null) {
            return Optional.empty();
        }
        Checkpoint checkpoint = checkpointRepository.findById(session.getCheckpointId()).orElse(null);
        if (checkpoint == null || checkpoint.getCheckpointId() == null) {
            return Optional.empty();
        }
        String pathSuffix = switch (file == null ? "" : file.toLowerCase()) {
            case "prompt" -> "prompt.txt";
            case "context" -> "context.md";
            case "transcript" -> "full.jsonl";
            default -> null;
        };
        if (pathSuffix == null) {
            return Optional.empty();
        }
        String path = checkpoint.getCheckpointId().substring(0, 2) + "/" + checkpoint.getCheckpointId().substring(2)
                + "/" + session.getSessionIndex() + "/" + pathSuffix;
        String revision = syncProperties.getBranch();
        Optional<String> revOpt = gitReader.resolveBranchCommitSha(checkpoint.getRepoId(), revision);
        if (revOpt.isEmpty()) {
            return Optional.empty();
        }
        return gitReader.getFileContent(checkpoint.getRepoId(), revOpt.get(), path);
    }

    @Override
    public Optional<NormalizedTranscriptDTO> getNormalizedTranscript(Long sessionId) {
        Optional<String> raw = getContent(sessionId, "transcript");
        if (raw.isEmpty()) {
            return Optional.empty();
        }
        return Optional.of(transcriptNormalizer.normalize(raw.get()));
    }
}

/**
 * Transcript parser for full.jsonl (OpenCode/Claude Code format)
 * Parses messages, file changes, tools used. Steps = user→assistant turn count.
 */

export interface FileDiff {
  file: string
  before: string
  after: string
  additions: number
  deletions: number
}

export interface ToolUse {
  callID: string
  tool: string
  input: unknown
  output?: unknown
  title?: string
}

export interface MessageView {
  id: string
  role: 'user' | 'assistant'
  text: string
  taskTitle?: string
  diffs?: FileDiff[]
  tools: ToolUse[]
  toolsCount: number
  reasoning?: string
  createdAt?: number
}

/// Metadata from `GET /session/transcript/normalized` (backend-normalized transcript).
export interface NormalizedTranscriptMeta {
  sourceFormat: string
  rawBytesLength: number
  warnings?: string[]
}

export interface ParsedTranscript {
  schemaVersion?: number
  meta?: NormalizedTranscriptMeta
  title?: string
  projectRoot?: string
  messages: MessageView[]
  fileChanges: { file: string; additions: number; deletions: number }[]
  stepsCount: number
}

interface TranscriptMessage {
  info?: {
    id?: string
    role?: string
    time?: { created?: number }
    summary?: { title?: string; diffs?: FileDiff[] }
  }
  parts?: Array<{
    type: string
    text?: string
    tool?: string
    callID?: string
    state?: { input?: unknown; output?: unknown; title?: string }
  }>
}

interface TranscriptRoot {
  info?: { title?: string; directory?: string }
  messages?: TranscriptMessage[]
}

/**
 * Strip project root from file path to get relative path
 */
export function stripProjectRoot(filePath: string, projectRoot?: string): string {
  if (!projectRoot) return filePath
  const normalized = filePath.replace(/\\/g, '/')
  const root = projectRoot.replace(/\\/g, '/').replace(/\/$/, '')
  if (normalized.startsWith(root + '/')) {
    return normalized.slice(root.length + 1)
  }
  return filePath
}

/**
 * Parse full.jsonl transcript
 */
export function parseTranscript(raw: string): ParsedTranscript | null {
  try {
    const root: TranscriptRoot = JSON.parse(raw)
    const messages: TranscriptMessage[] = root.messages ?? []
    const projectRoot = root.info?.directory

    const messageViews: MessageView[] = []
    const fileChangeMap = new Map<string, { additions: number; deletions: number }>()
    let stepsCount = 0

    for (const msg of messages) {
      const info = msg.info ?? {}
      const role = info.role === 'user' ? 'user' : 'assistant'
      const parts = msg.parts ?? []

      const textParts = parts.filter((p) => p.type === 'text').map((p) => p.text ?? '').join('\n')
      const reasoningPart = parts.find((p) => p.type === 'reasoning')
      const toolParts = parts.filter((p) => p.type === 'tool')
      const tools: ToolUse[] = toolParts.map((p) => ({
        callID: p.callID ?? '',
        tool: p.tool ?? '',
        input: p.state?.input,
        output: p.state?.output,
        title: p.state?.title,
      }))

      if (role === 'user') {
        stepsCount++
      }

      const diffs = info.summary?.diffs
      if (diffs) {
        for (const d of diffs) {
          const relPath = stripProjectRoot(d.file, projectRoot)
          const existing = fileChangeMap.get(relPath)
          const add = d.additions ?? 0
          const del = d.deletions ?? 0
          if (existing) {
            existing.additions += add
            existing.deletions += del
          } else {
            fileChangeMap.set(relPath, { additions: add, deletions: del })
          }
        }
      }

      messageViews.push({
        id: info.id ?? '',
        role,
        text: textParts.trim(),
        taskTitle: info.summary?.title,
        diffs: diffs?.map((d) => ({
          ...d,
          file: stripProjectRoot(d.file, projectRoot),
        })),
        tools,
        toolsCount: tools.length,
        reasoning: reasoningPart?.text,
        createdAt: info.time?.created,
      })
    }

    const fileChanges = Array.from(fileChangeMap.entries()).map(([file, stats]) => ({
      file,
      additions: stats.additions,
      deletions: stats.deletions,
    }))

    return {
      title: root.info?.title,
      projectRoot,
      messages: messageViews,
      fileChanges,
      stepsCount,
    }
  } catch {
    return null
  }
}

